const TOKEN_KEY = 'auth_token'
const USER_KEY = 'auth_user'

export type User = {
  id: string
  name: string
  email: string
}

export function getToken(): string | null {
  return localStorage.getItem(TOKEN_KEY)
}

export function setToken(token: string): void {
  localStorage.setItem(TOKEN_KEY, token)
}

export function clearToken(): void {
  localStorage.removeItem(TOKEN_KEY)
}

export function getStoredUser(): User | null {
  const raw = localStorage.getItem(USER_KEY)
  if (!raw) return null
  try {
    const parsed = JSON.parse(raw);
    return { id: parsed.id, name: parsed.name, email: parsed.email };
  } catch {
    return null
  }
}

export function setStoredUser(user: User): void {
  localStorage.setItem(USER_KEY, JSON.stringify(user))
}

export function clearStoredUser(): void {
  localStorage.removeItem(USER_KEY)
}

export function isLoggedIn(): boolean {
  return Boolean(getToken())
}

export type ProgressBucket = 'success' | 'warning' | 'danger'

export type MonthlyProgress = {
  month: string
  amount: number
  bucket: ProgressBucket
  isCurrent?: boolean
}

export type MoneyTone = 'success' | 'accent' | 'danger' | 'warning'
export type RowTone = 'success' | 'danger' | 'ink'

export type MoneyItem = {
  label: string
  amount: number
  signed?: boolean
  note?: string
}

export type MoneySection = {
  title: string
  tone: MoneyTone
  rowTone?: RowTone
  items: MoneyItem[]
  total?: { label: string; amount: number }
}

export type MoneyThisMonth = {
  sections: MoneySection[]
  outgoingsTotal: { label: string; amount: number }
}

export type SupportLink = {
  label: string
  href: string
}

export type FinancesSnapshot = {
  user: { firstName: string; email: string }
  period: string
  leftover: number
  status: { label: string; tone: 'warning' | 'success' | 'danger' }
  headline: string
  body: string
  insight: string
  money: MoneyThisMonth
  progress: MonthlyProgress[]
  progressNote: string
  support: { intro: string; links: SupportLink[] }
}

