import { Request, Response, Router } from 'express';
import { ZodError } from 'zod';
import { requireAuth } from '../middleware/auth.middleware';
import { overTimeProgressQuerySchema } from '../schemas/financial.schema';
import { getOverTimeProgress } from '../services/financial.service';

export const financialRouter = Router();

financialRouter.use(requireAuth);

financialRouter.get('/over-time-progress', async (req: Request, res: Response) => {
  const authUser = req.authUser;
  if (!authUser) {
    res.status(401).json({ error: 'Authentication required' });
    return;
  }

  try {
    const { month } = overTimeProgressQuerySchema.parse(req.query);
    const result = await getOverTimeProgress({
      userId: authUser.id,
      month: month === undefined ? undefined : Number(month),
    });
    res.status(200).json(result);
  } catch (error) {
    if (error instanceof ZodError) {
      res.status(400).json({
        error: 'ValidationError',
        details: error.issues.map((issue) => ({
          field: issue.path.join('.'),
          message: issue.message,
        })),
      });
      return;
    }

    console.error('Failed to compute over-time progress', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

