          transactionDate: utc(currentYear - 1, 10, 5),
        },
        {
          amount: 1400,
          type: 'outgoing',
          transactionDate: utc(currentYear - 1, 10, 20),
        },

        // October: zero income, some outgoings → progress 0
        {
          amount: 200,
          type: 'outgoing',
          transactionDate: utc(currentYear - 1, 9, 12),
        },

        // Out of window: September previous year — should be ignored.
        {
          amount: 9999,
          type: 'income',
          transactionDate: utc(currentYear - 1, 8, 1),
        },
        // Out of window: April current year — should be ignored.
        {
          amount: 5000,
          type: 'income',
          transactionDate: utc(currentYear, 3, 1),
        },
      ]);

      const response = await request(createApp())
        .get('/over-time-progress?month=03')
        .set('Authorization', `Bearer ${token}`);

      expect(response.status).toBe(200);
      expect(response.body).toEqual([
        {
          period: `Oct ${currentYear - 1}`,
          progress: 0,
          disposable_income: -200,
          is_now: false,
        },
        {
          period: `Nov ${currentYear - 1}`,
          progress: 30,
          disposable_income: 600,
          is_now: false,
        },
        {
          period: `Dec ${currentYear - 1}`,
          progress: 65,
          disposable_income: 1300,
          is_now: false,
        },
        {
          period: `Jan ${currentYear}`,
          progress: 10,
          disposable_income: 200,
          is_now: false,
        },
        {
          period: `Feb ${currentYear}`,
          progress: 50,
          disposable_income: 1000,
          is_now: false,
        },
        {
          period: `Mar ${currentYear}`,
          progress: 67,
          disposable_income: 2000,
          is_now: false,
        },
      ]);
    });

    it('defaults to the current month and year when no month query parameter is provided', async () => {
      const user = await createUser();
      const token = tokenForUser(user);

      const now = new Date();
      const currentYear = now.getUTCFullYear();
      const currentMonthIndex = now.getUTCMonth();

      await seedRecords(user.id, [
        {
          amount: 5000,
          type: 'income',
          transactionDate: utc(currentYear, currentMonthIndex, 5),
        },
        {
          amount: 1000,
          type: 'outgoing',
          transactionDate: utc(currentYear, currentMonthIndex, 20),
        },
      ]);

      const response = await request(createApp())
        .get('/over-time-progress')
        .set('Authorization', `Bearer ${token}`);

      expect(response.status).toBe(200);
      expect(response.body).toHaveLength(6);

      const last = response.body[5];
      const monthLabels = [
        'Jan',
        'Feb',
        'Mar',
        'Apr',
        'May',
        'Jun',
        'Jul',
        'Aug',
        'Sep',
        'Oct',
        'Nov',
        'Dec',
      ];
      expect(last).toEqual({
        period: `${monthLabels[currentMonthIndex]} ${currentYear}`,
        // 5000 income, 1000 outgoing → DTI 20% → progress 80
        progress: 80,
        disposable_income: 4000,
        is_now: true,
      });

      const earlierFlags: boolean[] = response.body
        .slice(0, 5)
        .map((point: { is_now: boolean }) => point.is_now);
      expect(earlierFlags.every((flag) => flag === false)).toBe(true);
    });
  });

  describe('financial health colour thresholds', () => {
    it.each([
      { totalIncome: 1000, totalOutgoing: 0, expectedProgress: 100 },
      { totalIncome: 1000, totalOutgoing: 350, expectedProgress: 65 }, // green boundary
      { totalIncome: 1000, totalOutgoing: 360, expectedProgress: 64 }, // amber boundary
      { totalIncome: 1000, totalOutgoing: 700, expectedProgress: 30 }, // amber boundary
      { totalIncome: 1000, totalOutgoing: 710, expectedProgress: 29 }, // red
      { totalIncome: 1000, totalOutgoing: 1500, expectedProgress: 0 }, // DTI > 100%
    ])(
      'computes progress=$expectedProgress for income=$totalIncome / outgoing=$totalOutgoing',
      async ({ totalIncome, totalOutgoing, expectedProgress }) => {
        const user = await createUser({ email: `user-${totalOutgoing}@example.com` });
        const token = tokenForUser(user);
        const currentYear = new Date().getUTCFullYear();
        const targetMonthIndex = 5; // June

        await seedRecords(user.id, [
          {
            amount: totalIncome,
            type: 'income',
            transactionDate: utc(currentYear, targetMonthIndex, 10),
          },
          {
            amount: totalOutgoing,
            type: 'outgoing',
            transactionDate: utc(currentYear, targetMonthIndex, 20),
          },
        ]);

        const response = await request(createApp())
          .get('/over-time-progress?month=06')
          .set('Authorization', `Bearer ${token}`);

        expect(response.status).toBe(200);
        const targetEntry = response.body[response.body.length - 1];
        expect(targetEntry.progress).toBe(expectedProgress);
        expect(targetEntry.disposable_income).toBe(totalIncome - totalOutgoing);
      },
    );
  });

  describe('edge cases', () => {
    it('returns zeroed buckets for months with no records', async () => {
      const user = await createUser();
      const token = tokenForUser(user);

      const response = await request(createApp())
        .get('/over-time-progress?month=06')
        .set('Authorization', `Bearer ${token}`);

      expect(response.status).toBe(200);
      expect(response.body).toHaveLength(6);
      for (const point of response.body) {
        expect(point.progress).toBe(0);
        expect(point.disposable_income).toBe(0);
      }
    });

    it('returns progress 0 when income is zero but outgoings exist', async () => {
      const user = await createUser();
      const token = tokenForUser(user);
      const currentYear = new Date().getUTCFullYear();

      await seedRecords(user.id, [
        {
          amount: 250,
          type: 'outgoing',
          transactionDate: utc(currentYear, 5, 5),
        },
      ]);

      const response = await request(createApp())
        .get('/over-time-progress?month=06')
        .set('Authorization', `Bearer ${token}`);

      expect(response.status).toBe(200);
      const target = response.body[response.body.length - 1];
      expect(target.progress).toBe(0);
      expect(target.disposable_income).toBe(-250);
    });

    it('isolates results to the authenticated user', async () => {
      const user = await createUser();
      const otherUser = await createUser({ email: 'other@example.com' });
      const token = tokenForUser(user);
      const currentYear = new Date().getUTCFullYear();

      await seedRecords(otherUser.id, [
        {
          amount: 9999,
          type: 'income',
          transactionDate: utc(currentYear, 5, 1),
        },
      ]);

      const response = await request(createApp())
        .get('/over-time-progress?month=06')
        .set('Authorization', `Bearer ${token}`);

      expect(response.status).toBe(200);
      for (const point of response.body) {
        expect(point.progress).toBe(0);
        expect(point.disposable_income).toBe(0);
      }
    });

    it('handles a window that crosses the year boundary', async () => {
      const user = await createUser();
      const token = tokenForUser(user);
      const currentYear = new Date().getUTCFullYear();

      // Asking for month=02 with 6 months lookback → Sep prev year through Feb current year.
      await seedRecords(user.id, [
        { amount: 1000, type: 'income', transactionDate: utc(currentYear - 1, 8, 15) },
        { amount: 1000, type: 'income', transactionDate: utc(currentYear, 1, 15) },
      ]);

      const response = await request(createApp())
        .get('/over-time-progress?month=02')
        .set('Authorization', `Bearer ${token}`);

      expect(response.status).toBe(200);
      expect(response.body.map((p: { period: string }) => p.period)).toEqual([
        `Sep ${currentYear - 1}`,
        `Oct ${currentYear - 1}`,
        `Nov ${currentYear - 1}`,
        `Dec ${currentYear - 1}`,
        `Jan ${currentYear}`,
        `Feb ${currentYear}`,
      ]);
      expect(response.body[0].disposable_income).toBe(1000);
      expect(response.body[5].disposable_income).toBe(1000);
    });
  });
});

