57	// Progress is a 0–100 score derived from DTI: lower DTI → more headroom →
58	// higher progress. (1 - DTI) * 100 clamps naturally onto the colour bands —
59	// 65–100 green, 30–64 amber, 0–29 red — matching the thresholds in the spec.
60	export const calculateProgress = (totalIncome: number, totalExpenditure: number): number => {
61	  const dti = calculateDti(totalIncome, totalExpenditure);
62	  if (dti === null) {
63	    return 0;
64	  }
65	  const raw = (1 - dti) * 100;
66	  return Math.max(0, Math.min(100, Math.round(raw)));
67	};
68	
69	export const colourForProgress = (progress: number): FinancialHealthColour => {
70	  if (progress >= 65) return 'green';
71	  if (progress >= 30) return 'amber';
72	  return 'red';
73	};
74	
75	const buildBuckets = (
76	  mostRecentYear: number,
77	  mostRecentMonth: number,
78	  lookbackMonths: number,
79	): MonthBucket[] => {
80	  const buckets: MonthBucket[] = [];
81	  for (let offset = lookbackMonths - 1; offset >= 0; offset -= 1) {
82	    const date = new Date(Date.UTC(mostRecentYear, mostRecentMonth - 1 - offset, 1));
83	    buckets.push({
84	      year: date.getUTCFullYear(),
85	      monthIndex: date.getUTCMonth(),
86	      totalIncome: 0,
87	      totalExpenditure: 0,
88	    });
89	  }
90	  return buckets;
91	};
92	
93	const bucketKey = (year: number, monthIndex: number): string => `${year}-${monthIndex}`;
94	
95	export const getOverTimeProgress = async (
96	  options: OverTimeProgressOptions,
97	): Promise<ProgressPoint[]> => {
98	  const config = loadConfig();
99	  const lookbackMonths = options.lookbackMonths ?? config.progressLookbackMonths;
100	  const now = options.now ?? new Date();
101	  const currentYear = now.getUTCFullYear();
102	  const currentMonth = now.getUTCMonth() + 1;
103	
104	  const targetYear = currentYear;
105	  const targetMonth = options.month ?? currentMonth;
106	
107	  const buckets = buildBuckets(targetYear, targetMonth, lookbackMonths);
108	
109	  const firstBucket = buckets[0];
110	  const lastBucket = buckets[buckets.length - 1];
111	  const windowStart = new Date(Date.UTC(firstBucket.year, firstBucket.monthIndex, 1, 0, 0, 0, 0));
112	  const windowEndExclusive = new Date(
113	    Date.UTC(lastBucket.year, lastBucket.monthIndex + 1, 1, 0, 0, 0, 0),
114	  );
115	  const windowEnd = new Date(windowEndExclusive.getTime() - 1);
116	
117	  const records = await getRepository().find({
118	    where: {
119	      userId: options.userId,
120	      transactionDate: Between(windowStart, windowEnd),
121	    },
122	  });
123	
124	  const bucketIndex = new Map<string, MonthBucket>();
125	  for (const bucket of buckets) {
126	    bucketIndex.set(bucketKey(bucket.year, bucket.monthIndex), bucket);
127	  }
128	
129	  for (const record of records) {
130	    const transactionDate = new Date(record.transactionDate);
131	    const key = bucketKey(transactionDate.getUTCFullYear(), transactionDate.getUTCMonth());
132	    const bucket = bucketIndex.get(key);
133	    if (!bucket) {
134	      continue;
135	    }
136	    const amount = Number(record.amount);
137	    if (record.type === 'income') {
138	      bucket.totalIncome += amount;
139	    } else {
140	      bucket.totalExpenditure += amount;
141	    }
142	  }
143	
144	  return buckets.map((bucket) => ({
145	    period: formatPeriod(bucket.year, bucket.monthIndex),
146	    progress: calculateProgress(bucket.totalIncome, bucket.totalExpenditure),
147	    disposable_income: bucket.totalIncome - bucket.totalExpenditure,
148	    is_now: bucket.year === currentYear && bucket.monthIndex === currentMonth - 1,
149	  }));
150	};

